mapper.select:
SELECT g.gvrnr_uid, g.gvrnr_nm, g.inspct_day, COUNT(s.gvrnr_uid)::int AS gvrnr_stat_cnt, r.cd_name FROM t_governor g INNER JOIN t_governor_stat s ON s.gvrnr_uid = g.gvrnr_uid INNER JOIN t_region_cd r ON r.cate_cd = g.cate_cd WHERE s.record_dttm >= CAST(#{startDate} AS DATE) AND s.record_dttm < CAST(#{endDate} AS DATE) + INTERVAL '1 day'
AND g.cate_cd = #{srchCity}
AND g.inspct_day = #{inspctDay}
AND g.gvrnr_nm LIKE CONCAT('%', #{srchCntnt}, '%')
GROUP BY g.gvrnr_uid, g.gvrnr_nm, g.inspct_day, r.cd_name ORDER BY g.gvrnr_nm ASC
